import React, { createContext, useState, useContext, useEffect } from 'react';
import * as userService from '../services/userService';
import { useAuth } from './AuthContext';
import toast from 'react-hot-toast';

const CartContext = createContext();

export const useCart = () => {
  const context = useContext(CartContext);
  if (!context) {
    throw new Error('useCart must be used within CartProvider');
  }
  return context;
};

export const CartProvider = ({ children }) => {
  const [cart, setCart] = useState([]);
  const [loading, setLoading] = useState(false);
  const { isAuthenticated } = useAuth();

  useEffect(() => {
    if (isAuthenticated) {
      loadCart();
    } else {
      // Load from localStorage for non-authenticated users
      const localCart = JSON.parse(localStorage.getItem('cart') || '[]');
      setCart(localCart);
    }
  }, [isAuthenticated]);

  const loadCart = async () => {
    try {
      setLoading(true);
      const response = await userService.getCart();
      setCart(response.data);
    } catch (error) {
      console.error('Load cart error:', error);
    } finally {
      setLoading(false);
    }
  };

  const addToCart = async (productId, quantity = 1) => {
    try {
      if (isAuthenticated) {
        const response = await userService.addToCart(productId, quantity);
        setCart(response.data);
        toast.success('Added to cart');
      } else {
        // Handle local storage for non-authenticated users
        const localCart = [...cart];
        const existingItem = localCart.find(item => item.product._id === productId);

        if (existingItem) {
          existingItem.quantity += quantity;
        } else {
          // In real app, fetch product details
          localCart.push({ product: { _id: productId }, quantity });
        }

        setCart(localCart);
        localStorage.setItem('cart', JSON.stringify(localCart));
        toast.success('Added to cart');
      }
    } catch (error) {
      toast.error('Failed to add to cart');
      console.error('Add to cart error:', error);
    }
  };

  const updateQuantity = async (productId, quantity) => {
    try {
      if (quantity < 1) {
        return removeFromCart(productId);
      }

      if (isAuthenticated) {
        const response = await userService.updateCartItem(productId, quantity);
        setCart(response.data);
      } else {
        const localCart = cart.map(item =>
          item.product._id === productId ? { ...item, quantity } : item
        );
        setCart(localCart);
        localStorage.setItem('cart', JSON.stringify(localCart));
      }
    } catch (error) {
      toast.error('Failed to update cart');
      console.error('Update cart error:', error);
    }
  };

  const removeFromCart = async (productId) => {
    try {
      if (isAuthenticated) {
        const response = await userService.removeFromCart(productId);
        setCart(response.data);
        toast.success('Removed from cart');
      } else {
        const localCart = cart.filter(item => item.product._id !== productId);
        setCart(localCart);
        localStorage.setItem('cart', JSON.stringify(localCart));
        toast.success('Removed from cart');
      }
    } catch (error) {
      toast.error('Failed to remove from cart');
      console.error('Remove from cart error:', error);
    }
  };

  const clearCart = async () => {
    try {
      if (isAuthenticated) {
        await userService.clearCart();
      }
      setCart([]);
      localStorage.removeItem('cart');
    } catch (error) {
      console.error('Clear cart error:', error);
    }
  };

  const getCartTotal = () => {
    return cart.reduce((total, item) => {
      return total + (item.product?.price || 0) * item.quantity;
    }, 0);
  };

  const getCartCount = () => {
    return cart.reduce((count, item) => count + item.quantity, 0);
  };

  const value = {
    cart,
    loading,
    addToCart,
    updateQuantity,
    removeFromCart,
    clearCart,
    getCartTotal,
    getCartCount
  };

  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
};
